typedef std::vector<int> vint;

class A {
public:
    vint a = {1,2,3,4,5,6,7};
    vint::iterator a_begin() {
        return a.begin();
    }
    vint::iterator a_end() {
        return a.end();
    }
};

namespace {
    // Special iterator data structure for python
    template <typename T>
    struct PySequenceIterator {
        PySequenceIterator(const T & begin, const T & end, py::object ref) : begin(begin), end(end), ref(ref) {}
        py::object next() {
            if (begin == end)
                throw py::stop_iteration();
            return py::cast(*(begin++));
        }

        int len() {
            return std::distance(begin, end);
        }

        py::object getitem(int i) {
            return py::cast(begin[i]);
        }

        T begin;
        T end;
        py::object ref; // keep a reference
        size_t index = 0;
    };
};

void init_test(py::module &m) {
    py::module sub = m.def_submodule("isolatedtest", "isolatedtest");
